@using sv_839ed790628e4083a52bb9a224121f23.Services
@inject ISettingsService SettingsService

<div class="profile-section">
    <h4>Profile</h4>
    <p class="text-muted">Manage your personal information and public profile.</p>

    @if (_loading)
    {
        <div class="text-center py-4"><div class="spinner-border text-primary" role="status"></div></div>
    }
    else
    {
        <div class="profile-layout">
            <div class="avatar-area">
                <div class="avatar-preview">
                    <img src="@_avatarUrl" alt="Avatar" class="avatar-img" />
                </div>
                <div class="avatar-url-display">
                    <label class="form-label">Avatar URL</label>
                    <input type="url" class="form-control form-control-sm" @bind="_avatarUrl" />
                </div>
            </div>

            <div class="profile-fields">
                <div class="mb-3">
                    <label class="form-label">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>
        </div>

        <div class="d-flex gap-2 mt-3">
            <button class="btn btn-primary" @onclick="SaveAsync">Save Changes</button>
            <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
        </div>

        @if (_showSuccess)
        {
            <div class="alert alert-success mt-3 fade-in" role="alert">
                ✅ Profile saved successfully!
            </div>
        }
    }
</div>

@code {
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private UserProfile? _savedProfile;
    private bool _loading = true;
    private bool _showSuccess;

    protected override async Task OnInitializedAsync()
    {
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _avatarUrl = p.AvatarUrl;
        _bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void Discard()
    {
        if (_savedProfile is not null)
            ApplyProfile(_savedProfile);
    }
}

