toolArgs.file_text:
@using sv_839ed790628e4083a52bb9a224121f23.Services
@inject ISettingsService SettingsService

<div class="notifications-section">
    <h4>Notifications</h4>
    <p class="text-muted">Choose how and when you'd like to be notified.</p>

    @if (_loading)
    {
        <div class="text-center py-4"><div class="spinner-border text-primary" role="status"></div></div>
    }
    else
    {
        <div class="notification-toggles">
            <div class="toggle-row">
                <div>
                    <strong>Email Notifications</strong>
                    <div class="text-muted small">Receive notifications via email</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_emailNotifications"
                           @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
                </div>
            </div>
            <div class="toggle-row">
                <div>
                    <strong>Push Notifications</strong>
                    <div class="text-muted small">Receive push notifications in your browser</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_pushNotifications"
                           @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
                </div>
            </div>
            <div class="toggle-row">
                <div>
                    <strong>Weekly Digest</strong>
                    <div class="text-muted small">Get a weekly summary of activity</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_weeklyDigest"
                           @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
                </div>
            </div>
        </div>

        <hr />

        <h6>Muted Channels</h6>
        <p class="text-muted small">Uncheck channels you want to receive notifications from.</p>
        <div class="channel-list">
            @foreach (var channel in _allChannels)
            {
                var isMuted = _mutedChannels.Contains(channel);
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@isMuted"
                           @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel}")">
                        #@channel
                    </label>
                </div>
            }
        </div>

        <button class="btn btn-primary mt-3" @onclick="SaveAsync">Save Preferences</button>

        @if (_showSuccess)
        {
            <div class="alert alert-success mt-3 fade-in" role="alert">
                ✅ Notification preferences saved!
            </div>
        }
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _mutedChannels = [];
    private List<string> _allChannels = [];
    private bool _loading = true;
    private bool _showSuccess;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = [.. prefs.MutedChannels];
        _allChannels = [.. prefs.MutedChannels];
        _loading = false;
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted && !_mutedChannels.Contains(channel))
            _mutedChannels.Add(channel);
        else if (!muted)
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, [.. _mutedChannels]);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

