@using sv_839ed790628e4083a52bb9a224121f23.Services

@if (_showDialog)
{
    <div class="modal-backdrop show"></div>
    <div class="modal d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke this session?</p>
                    @if (_session is not null)
                    {
                        <div class="text-muted">
                            <strong>@_session.Device</strong> — @_session.Location
                        </div>
                    }
                    <p class="mt-2 text-danger small">This will immediately sign out this device.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public EventCallback<string> OnConfirm { get; set; }

    private bool _showDialog;
    private ActiveSession? _session;

    public void Show(ActiveSession session)
    {
        _session = session;
        _showDialog = true;
        StateHasChanged();
    }

    private void Cancel()
    {
        _showDialog = false;
        _session = null;
    }

    private async Task Confirm()
    {
        if (_session is not null)
        {
            await OnConfirm.InvokeAsync(_session.Id);
        }
        _showDialog = false;
        _session = null;
    }
}

