@using sv_839ed790628e4083a52bb9a224121f23.Services
@inject ISettingsService SettingsService

<div class="security-section">
    <h4>Security</h4>
    <p class="text-muted">Manage your password, two-factor authentication, and active sessions.</p>

    @if (_loading)
    {
        <div class="text-center py-4"><div class="spinner-border text-primary" role="status"></div></div>
    }
    else
    {
        <ChangePasswordPanel OnChangePassword="HandleChangePassword" />

        <hr />

        <div class="tfa-section">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <div class="text-muted small">Add an extra layer of security to your account</div>
                </div>
                <div class="d-flex align-items-center gap-2">
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    <div class="form-check form-switch mb-0">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@_twoFactorEnabled"
                               @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                    </div>
                </div>
            </div>
        </div>

        @if (_lastPasswordChange.HasValue)
        {
            <div class="text-muted small mt-3">
                🕐 Last password change: @_lastPasswordChange.Value.ToString("MMMM d, yyyy")
            </div>
        }

        <hr />

        <ActiveSessionsTable Sessions="_sessions"
                             CurrentSessionId="@_currentSessionId"
                             OnRevokeRequested="RequestRevoke" />

        <RevokeSessionDialog @ref="_revokeDialog" OnConfirm="HandleRevokeSession" />
    }
</div>

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private string _currentSessionId = "sess-1";
    private RevokeSessionDialog _revokeDialog = default!;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = [.. settings.Sessions];
        _loading = false;
    }

    private async Task HandleChangePassword((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _lastPasswordChange = DateTime.UtcNow;
    }

    private void RequestRevoke(ActiveSession session)
    {
        _revokeDialog.Show(session);
    }

    private async Task HandleRevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _sessions.RemoveAll(s => s.Id == sessionId);
    }
}

.security-section h4 {
    margin-bottom: 0.25rem;
}

.tfa-section {
    padding: 0.75rem 0;
}

@using sv_839ed790628e4083a52bb9a224121f23.Services
@inject ISettingsService SettingsService

<div class="appearance-section">
    <h4>Appearance</h4>
    <p class="text-muted">Customize how the application looks and feels.</p>

    @if (_loading)
    {
        <div class="text-center py-4"><div class="spinner-border text-primary" role="status"></div></div>
    }
    else
    {
        <div class="appearance-layout">
            <div class="appearance-controls">
                <div class="mb-4">
                    <h6>Theme</h6>
                    <div class="d-flex gap-3">
                        @foreach (var theme in _themes)
                        {
                            <label class="theme-option @(_theme == theme ? "selected" : "")">
                                <input type="radio" name="theme" value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" class="d-none" />
                                <span class="theme-icon">@GetThemeIcon(theme)</span>
                                <span>@theme</span>
                            </label>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <h6>Font Size</h6>
                    <div class="d-flex gap-3">
                        @foreach (var size in _fontSizes)
                        {
                            <label class="size-option @(_fontSize == size ? "selected" : "")">
                                <input type="radio" name="fontSize" value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" class="d-none" />
                                @size
                            </label>
                        }
                    </div>
                </div>

                <div class="mb-4">
                    <h6>Language</h6>
                    <select class="form-select" style="max-width: 250px;"
                            @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                <div class="mb-4">
                    <div class="d-flex justify-content-between align-items-center" style="max-width: 300px;">
                        <div>
                            <strong>Compact Mode</strong>
                            <div class="text-muted small">Reduce spacing and padding</div>
                        </div>
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" role="switch"
                                   checked="@_compactMode"
                                   @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                        </div>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync">Save</button>

                @if (_showSuccess)
                {
                    <div class="alert alert-success mt-3 fade-in" role="alert">
                        ✅ Appearance settings saved!
                    </div>
                }
            </div>

            <div class="preview-area">
                <h6>Live Preview</h6>
                <div class="preview-card @GetPreviewClasses()">
                    <div class="preview-header">
                        <strong>Preview Card</strong>
                    </div>
                    <div class="preview-body">
                        <p>This is how your content will look with the selected settings.</p>
                        <button class="preview-button">Sample Button</button>
                    </div>
                    <div class="preview-footer">
                        <span class="text-muted">@_language · @_fontSize · @_theme theme</span>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _loading = true;
    private bool _showSuccess;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_theme.ToLowerInvariant() switch { "dark" => "preview-dark", "system" => "preview-system", _ => "preview-light" });
