toolArgs.file_text:
.appearance-section h4 {
    margin-bottom: 0.25rem;
}

.appearance-layout {
    display: flex;
    gap: 2.5rem;
    margin-top: 1.5rem;
}

.appearance-controls {
    flex: 1;
}

.theme-option {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.25rem;
    padding: 0.75rem 1.25rem;
    border: 2px solid #dee2e6;
    border-radius: 0.5rem;
    cursor: pointer;
    transition: border-color 0.15s, background-color 0.15s;
    font-size: 0.9rem;
}

.theme-option:hover {
    border-color: #adb5bd;
}

.theme-option.selected {
    border-color: #0d6efd;
    background: #e7f1ff;
}

.theme-icon {
    font-size: 1.5rem;
}

.size-option {
    padding: 0.5rem 1.25rem;
    border: 2px solid #dee2e6;
    border-radius: 0.375rem;
    cursor: pointer;
    transition: border-color 0.15s, background-color 0.15s;
    font-size: 0.9rem;
}

.size-option:hover {
    border-color: #adb5bd;
}

.size-option.selected {
    border-color: #0d6efd;
    background: #e7f1ff;
    font-weight: 500;
}

/* Preview area */
.preview-area {
    width: 300px;
    flex-shrink: 0;
}

.preview-card {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.3s ease;
}

.preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
}

.preview-body {
    padding: 1rem;
}

.preview-body p {
    margin-bottom: 0.75rem;
}

.preview-footer {
    padding: 0.5rem 1rem;
    border-top: 1px solid #dee2e6;
    font-size: 0.8rem;
}

.preview-button {
    padding: 0.35rem 0.75rem;
    border: 1px solid #0d6efd;
    background: #0d6efd;
    color: white;
    border-radius: 0.25rem;
    cursor: default;
    font-size: inherit;
}

/* Theme variants */
.preview-light {
    background: #fff;
    color: #212529;
}

.preview-dark {
    background: #1a1a2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-dark .preview-header {
    background: #16213e;
    border-color: #444;
}

.preview-dark .preview-footer {
    border-color: #444;
}

.preview-dark .preview-button {
    background: #4a90d9;
    border-color: #4a90d9;
}

.preview-system {
    background: linear-gradient(135deg, #fff 50%, #1a1a2e 50%);
    color: #212529;
}

/* Font size variants */
.preview-font-sm {
    font-size: 0.8rem;
}

.preview-font-md {
    font-size: 0.95rem;
}

.preview-font-lg {
    font-size: 1.15rem;
}

/* Compact mode */
.preview-compact .preview-header {
    padding: 0.4rem 0.75rem;
}

.preview-compact .preview-body {
    padding: 0.5rem 0.75rem;
}

.preview-compact .preview-footer {
    padding: 0.25rem 0.75rem;
}

.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-5px); }
    to { opacity: 1; transform: translateY(0); }
}

