@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="s => _activeSection = s" />

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
}

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 120px);
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    margin: -0.5rem;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

